import React, { useEffect, useRef, useCallback } from 'react';
import { useParams, Link } from 'react-router-dom';
import styled from 'styled-components';
import { useTranslation } from 'react-i18next';

// Components
import ProductCard from '../components/ProductCard';
import Loading from '../components/Loading';
import Error from '../components/Error';

// API
import { getStoreDiscounts } from '../utils/api';

const Container = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 1.5rem;

  @media (max-width: 480px) {
    padding: 1rem 0.75rem;
  }
`;

const BackLink = styled(Link)`
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  color: ${({ theme }) => theme.colors.primary};
  font-weight: 500;
  margin-bottom: 1rem;

  &:hover {
    text-decoration: underline;
  }

  @media (max-width: 480px) {
    font-size: 0.9rem;
    margin-bottom: 0.75rem;
  }
`;

const StoreHeader = styled.div`
  margin-bottom: 2rem;
  display: flex;
  justify-content: space-between;

  @media (max-width: 480px) {
    margin-bottom: 1.25rem;
  }
`;

const StoreName = styled.h1`
  font-size: ${({ theme }) => theme.fontSizes['2xl']};
  font-weight: 700;
  margin-bottom: 0.5rem;
  color: ${({ theme }) => theme.colors.text};

  @media (max-width: 480px) {
    font-size: 1.5rem;
    margin-bottom: 0.3rem;
  }
`;

const StoreLocation = styled.p`
  font-size: ${({ theme }) => theme.fontSizes.md};
  color: ${({ theme }) => theme.colors.textLight};
  text-align: right;

  @media (max-width: 480px) {
    font-size: 0.9rem;
  }
`;

const SectionTitle = styled.h2`
  font-size: ${({ theme }) => theme.fontSizes.xl};
  font-weight: 600;
  margin-bottom: 1.5rem;
  color: ${({ theme }) => theme.colors.text};

  @media (max-width: 480px) {
    font-size: 1.25rem;
    margin-bottom: 1rem;
  }
`;

const Grid = styled.div`
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.5rem;

  @media (max-width: 768px) {
    grid-template-columns: repeat(2, 1fr);
    gap: 1rem;
  }

  @media (max-width: 480px) {
    grid-template-columns: repeat(2, 1fr);
    gap: 0.75rem;
  }
`;

const EmptyState = styled.div`
  text-align: center;
  padding: 3rem 1rem;
  color: ${({ theme }) => theme.colors.textLight};

  @media (max-width: 480px) {
    padding: 2rem 0.5rem;
    font-size: 0.9rem;
  }
`;

const StoreDetail = () => {
  const { storeId } = useParams();
  const { t } = useTranslation();
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState(null);
  const [data, setData] = React.useState(null);
  const fetchingRef = useRef(false);

  const fetchData = useCallback(async () => {
    if (fetchingRef.current) return;

    try {
      setLoading(true);
      setError(null);
      fetchingRef.current = true;

      console.log(`Fetching store discounts for ID: ${storeId}`);
      const result = await getStoreDiscounts(storeId);
      console.log('Store discounts result:', result);

      setData(result);
      setLoading(false);
    } catch (err) {
      console.error('Error fetching store discounts:', err);
      setError(err);
      setLoading(false);
    } finally {
      fetchingRef.current = false;
    }
  }, [storeId]);

  // Загружаем данные при монтировании компонента или изменении storeId
  useEffect(() => {
    fetchData();

    // Очищаем состояние при размонтировании
    return () => {
      fetchingRef.current = false;
    };
  }, [fetchData, storeId]);

  const store = data?.store;
  const discounts = data?.discounts || [];

  return (
    <Container>
      <BackLink to="/">
        ← {t('backToStores')}
      </BackLink>

      {loading ? (
        <Loading />
      ) : error ? (
        <Error onRetry={() => fetchData()} />
      ) : store ? (
        <>
          <StoreHeader>
            <StoreName>{store.name}</StoreName>
            <StoreLocation>{store.city.charAt(0).toUpperCase() + store.city.slice(1)}</StoreLocation>
          </StoreHeader>

          <SectionTitle>{t('discountedProducts')}</SectionTitle>

          {discounts.length > 0 ? (
            <Grid>
              {discounts.map(product => (
                <ProductCard 
                  key={product.id} 
                  product={product} 
                  store={store}
                />
              ))}
            </Grid>
          ) : (
            <EmptyState>
              <p>{t('noDiscounts')}</p>
            </EmptyState>
          )}
        </>
      ) : (
        <EmptyState>
          <p>{t('storeNotFound')}</p>
        </EmptyState>
      )}
    </Container>
  );
};

export default StoreDetail;
